def render_icon(name, fill=False):
    """Return <svg><use/></svg> markup referencing the inline sprite."""
    ref = f'#i-{name}-fill' if fill else f'#i-{name}'
    cls = 'ic ic-fill' if fill else 'ic'
    return f'<svg class="{cls}" aria-hidden="true"><use href="{ref}"/></svg>'
